    driverUrl: String,
    executorId: String,
    hostname: String,
    cores: Int,
    appId: String,
    workerUrl: Option[String],
    userClassPath: Seq[URL]) {
  ……
  env.rpcEnv.setupEndpoint("Executor", new CoarseGrainedExecutorBackend(
